class Account:
    def __init__(self, owner, balance):
        self.owner = owner
        self.balance = max(0, balance)

    def deposit(self, amount):
        if amount > 0:
            self.balance += amount
        return self.balance

    def withdraw(self, amount):
        if amount > 0 and amount <= self.balance:
            self.balance -= amount
            return True
        return False

    def summary(self):
        return f"{self.owner}: ${self.balance}"

